#nullable enable // autogenerated

using System.Xml;
using MVZ2.IO;

namespace MVZ2.Metas
{
    public class AlmanacVariableOperationDivide : AlmanacVariableOperationUnary
    {
        public bool reverse;
        public AlmanacVariableOperationDivide(AlmanacVariableReference reference) : base(reference)
        {
        }

        public override double Operate(AlmanacVariableContext context, double value)
        {
            if (reverse)
            {
                return GetOperand(context) / value;
            }
            return value / GetOperand(context);
        }
        public static AlmanacVariableOperationDivide? FromXmlNode(XmlNode node, string defaultNsp)
        {
            var reference = XMLHelper.GetAlmanacVariableReference(node, defaultNsp);
            if (reference == null)
            {
                Log.LogError($"Cannot load variable reference of {nameof(AlmanacVariableOperationDivide)}.");
                return null;
            }
            var reverse = node.GetAttributeBool("reverse") ?? false;
            return new AlmanacVariableOperationDivide(reference)
            {
                reverse = reverse
            };
        }
    }
}
